import{_ as a,o as t,c as i,a3 as o}from"./chunks/framework.BveOjhN0.js";const h=JSON.parse('{"title":"Multi-Provider Email Delivery","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Multi-Provider Email Delivery | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/developer-guide/multi-provider-email"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Multi-Provider Email Delivery | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/developer-guide/multi-provider-email"}]]},"headers":[],"relativePath":"developer-guide/multi-provider-email.md","filePath":"developer-guide/multi-provider-email.md","lastUpdated":1784471162000}'),d={name:"developer-guide/multi-provider-email.md"};function l(r,e,s,n,c,m){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="multi-provider-email-delivery" tabindex="-1">Multi-Provider Email Delivery <a class="header-anchor" href="#multi-provider-email-delivery" aria-label="Permalink to &quot;Multi-Provider Email Delivery&quot;">​</a></h1><p>Platform infrastructure for Central and Tenant outgoing mail. SMTP remains fully supported; Postmark and Mailgun are first-class API drivers.</p><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><p>Application code continues to send through Laravel <code>Mail</code> / Notification mail channels. Runtime provider selection is handled by:</p><table tabindex="0"><thead><tr><th>Class</th><th>Role</th></tr></thead><tbody><tr><td><code>EmailConfigResolver</code></td><td>Builds <code>EmailConfig</code> from Central / Tenant settings (+ env fallback)</td></tr><tr><td><code>EmailManager</code></td><td>Clears prior secrets, applies config to Laravel mailers, calls <code>Mail::forgetMailers()</code></td></tr><tr><td><code>EmailDriverInterface</code></td><td>Provider-specific config mapping + validation</td></tr><tr><td><code>SupportsWebhooks</code></td><td>Optional delivery webhook verify/parse/catalog</td></tr><tr><td><code>ApplyEmailRuntimeConfig</code></td><td>Queue middleware that re-applies config on the <code>emails</code> worker, then clears secrets</td></tr><tr><td><code>ApplyCentralEmailRuntimeConfig</code></td><td>Central HTTP middleware (<code>central.mail</code>) re-applies Central mail every request</td></tr></tbody></table><p>Drivers are registered in <code>config/email.php</code>.</p><h2 id="tenant-modes" tabindex="-1">Tenant modes <a class="header-anchor" href="#tenant-modes" aria-label="Permalink to &quot;Tenant modes&quot;">​</a></h2><table tabindex="0"><thead><tr><th><code>mail_mode</code></th><th>Behavior</th></tr></thead><tbody><tr><td><code>system</code> (default)</td><td>Inherit Central provider + From identity</td></tr><tr><td><code>custom</code></td><td>Tenant-owned SMTP / Postmark / Mailgun</td></tr></tbody></table><p>Backward compatible: a filled tenant <code>mail_host</code> without <code>mail_mode</code> still counts as custom SMTP. Run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> email:migrate-tenant-mail-modes</span></span></code></pre></div><h2 id="settings-keys" tabindex="-1">Settings keys <a class="header-anchor" href="#settings-keys" aria-label="Permalink to &quot;Settings keys&quot;">​</a></h2><p>Shared mail group keys (Central <code>system_settings</code> / Tenant <code>tenant_settings</code>):</p><ul><li><code>mail_provider</code> (canonical) / <code>mail_driver</code> (legacy alias, kept in sync)</li><li>SMTP: <code>mail_host</code>, <code>mail_port</code>, <code>mail_username</code>, <code>mail_password</code>, <code>mail_encryption</code></li><li>Postmark: <code>mail_postmark_token</code>, <code>mail_postmark_message_stream</code></li><li>Mailgun: <code>mail_mailgun_secret</code>, <code>mail_mailgun_domain</code>, <code>mail_mailgun_endpoint</code></li><li>Webhooks: <code>mail_webhook_secret</code>, <code>mail_webhook_events</code></li><li>Identity: <code>mail_from_name</code>, <code>mail_from_address</code>, <code>mail_reply_to</code>, <code>mail_timeout</code></li><li>Tenant only: <code>mail_mode</code></li></ul><p>Secrets are encrypted at rest and masked as <code>********</code> in admin APIs.</p><h2 id="test-email" tabindex="-1">Test email <a class="header-anchor" href="#test-email" aria-label="Permalink to &quot;Test email&quot;">​</a></h2><ul><li>Central: <code>POST /api/central/v1/system-settings/test-mail</code></li><li>Tenant: <code>POST /api/tenant/v1/settings/test-mail</code></li></ul><p>Optional <code>settings</code> object tests unsaved draft credentials. Response includes <code>success</code>, <code>code</code>, <code>provider</code>, <code>duration_ms</code>.</p><h2 id="email-logs" tabindex="-1">Email logs <a class="header-anchor" href="#email-logs" aria-label="Permalink to &quot;Email logs&quot;">​</a></h2><ul><li>Central: <code>GET /api/central/v1/email-logs</code></li><li>Tenant: <code>GET /api/tenant/v1/email-logs</code></li><li>Show: includes <code>body_html</code> / <code>body_text</code> when stored (list omits bodies; exposes <code>has_body</code>)</li><li>Permissions: <code>email-logs.list</code>, <code>email-logs.view</code>, <code>email-logs.resend</code></li><li>Retention: <code>php artisan email-logs:prune</code> (scheduled weekly)</li></ul><h3 id="body-logging-proof" tabindex="-1">Body logging (proof) <a class="header-anchor" href="#body-logging-proof" aria-label="Permalink to &quot;Body logging (proof)&quot;">​</a></h3><p>By default (<code>EMAIL_LOGS_STORE_BODY=true</code>), HTML and plain-text bodies are stored with each log so Central and Tenant admins can prove who received what. Set <code>EMAIL_LOGS_STORE_BODY=false</code> only for emergency size/PII lockdown. Bodies prune with the log row.</p><h3 id="manual-resend" tabindex="-1">Manual resend <a class="header-anchor" href="#manual-resend" aria-label="Permalink to &quot;Manual resend&quot;">​</a></h3><p><code>POST …/email-logs/{uuid}/resend</code> (<code>email-logs.resend</code>) reconstructs the message from stored recipients + subject + bodies via <code>EmailResendService</code>. Creates a <strong>new</strong> log (<code>meta.resent_from_uuid</code>); does not mutate the original. Requires a stored body (422 when missing).</p><h2 id="delivery-webhooks" tabindex="-1">Delivery webhooks <a class="header-anchor" href="#delivery-webhooks" aria-label="Permalink to &quot;Delivery webhooks&quot;">​</a></h2><p>See <a href="/developer-guide/email-webhooks">Email provider webhooks</a> for ingress URLs, event multiselect, and signature verification.</p><h2 id="queue-workers" tabindex="-1">Queue workers <a class="header-anchor" href="#queue-workers" aria-label="Permalink to &quot;Queue workers&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> queue:work</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --queue=emails,default</span></span></code></pre></div><p>Restart workers after changing mail credentials (<code>queue:restart</code>).</p><h2 id="extending-with-a-new-provider" tabindex="-1">Extending with a new provider <a class="header-anchor" href="#extending-with-a-new-provider" aria-label="Permalink to &quot;Extending with a new provider&quot;">​</a></h2><ol><li>Implement <code>EmailDriverInterface</code> (and <code>SupportsWebhooks</code> when applicable)</li><li>Register in <code>config/email.php</code> → <code>drivers</code></li><li>Add settings catalog keys + validation + UI conditional fields</li><li>Nothing else — notifications/mailables stay unchanged</li></ol>',30)])])}const u=a(d,[["render",l]]);export{h as __pageData,u as default};
